/**
 * Sets a new location and radius for this circle, based upon another circle.
 *
 * @param circle The circle to copy the position and radius of.
 */
public void set(Circle circle) {
    this.x = circle.x;
    this.y = circle.y;
    this.radius = circle.radius;
}
